<?php require '../config.php'; $msg=''; if($_SERVER['REQUEST_METHOD']==='POST'){ verify_csrf(); $email=strtolower(trim($_POST['email']??'')); $pass=$_POST['password']??''; $st=$pdo->prepare('SELECT * FROM admins WHERE email=?');$st->execute([$email]);$a=$st->fetch(); if($a && (int)($a['is_active'] ?? 1)===1 && password_verify($pass,$a['password_hash'])){session_regenerate_id(true);$_SESSION['admin_id']=$a['id'];$_SESSION['admin_name']=$a['name'];$pdo->prepare('UPDATE admins SET last_login_at=NOW() WHERE id=?')->execute([$a['id']]);log_activity($pdo,'admin_login','Admin login');redirect('/admin/dashboard.php');} else {$msg='Invalid admin login.';} } ?>
<!doctype html><html><head><title>Admin Login</title><link rel="stylesheet" href="/style.css"></head><body><div class="top"><div class="brand">Karacraft Admin</div></div><div class="card form"><h1>Admin Login</h1><?php if($msg):?><div class="alert"><?=h($msg)?></div><?php endif;?><form method="post"><?=csrf_field()?><label>Email</label><input type="email" name="email" required value="admin@hosting.local"><label>Password</label><input type="password" name="password" required><button class="btn">Login</button><p><a href="/admin/forgot_password.php">Forgot admin password?</a></p></form></div></body></html>
